<?php
declare(strict_types=1);
if(PHP_SAPI!=='cli'){http_response_code(404);exit('Not found.');}
require_once dirname(__DIR__).'/api/intelligence/_intelligence.php';$date=$argv[1]??date('Y-m-d');$period=max(7,min(365,(int)($argv[2]??30)));$pdo=mg_db();$merchants=$pdo->query('SELECT DISTINCT merchant_user_id FROM demand_fact_daily')->fetchAll(PDO::FETCH_COLUMN);$start=date('Y-m-d',strtotime($date.' -'.($period-1).' days'));$previousStart=date('Y-m-d',strtotime($start.' -'.$period.' days'));$previousEnd=date('Y-m-d',strtotime($start.' -1 day'));
foreach($merchants as $merchantId){$stmt=$pdo->prepare('SELECT COALESCE(SUM(items_issued),0) items,COALESCE(SUM(issued_value_cents),0) value,COALESCE(SUM(impressions),0) impressions,COALESCE(SUM(opens),0) opens,COALESCE(SUM(claims),0) claims,COALESCE(SUM(redemptions),0) redemptions,COALESCE(SUM(media_completions),0) completions FROM demand_fact_daily WHERE merchant_user_id=? AND metric_date BETWEEN ? AND ?');$stmt->execute([(int)$merchantId,$start,$date]);$now=$stmt->fetch();$stmt->execute([(int)$merchantId,$previousStart,$previousEnd]);$before=$stmt->fetch();$demand=mg_intelligence_clamp(log10(1+(float)$now['items'])*25);$engagement=mg_intelligence_clamp(100*mg_intelligence_safe_div((float)$now['opens']+(float)$now['completions'],max(1,(float)$now['impressions']*2)));$fulfillment=mg_intelligence_clamp(100*mg_intelligence_safe_div((float)$now['claims'],max(1,(float)$now['items'])));$redemption=mg_intelligence_clamp(100*mg_intelligence_safe_div((float)$now['redemptions'],max(1,(float)$now['claims'])));$growth=mg_intelligence_growth((float)$now['value'],(float)$before['value']);$insights=[];if($growth!==null&&$growth>.15)$insights[]=['type'=>'growth','severity'=>'positive','message'=>'Issued value is growing faster than 15% versus the prior period.'];if($fulfillment<35&&$now['items']>10)$insights[]=['type'=>'claim_gap','severity'=>'warning','message'=>'Claim conversion is below 35%; review delivery timing and claim instructions.'];if($redemption<40&&$now['claims']>10)$insights[]=['type'=>'redemption_gap','severity'=>'warning','message'=>'Redemption conversion is below 40%; review merchant eligibility and expiration terms.'];if(!$insights)$insights[]=['type'=>'baseline','severity'=>'neutral','message'=>'Demand and engagement are within the current operating baseline.'];$forecastStmt=$pdo->prepare("SELECT COALESCE(SUM(dfp.predicted_value),0) FROM demand_forecast_runs dfr INNER JOIN demand_forecast_models dfm ON dfm.id=dfr.model_id INNER JOIN demand_forecast_points dfp ON dfp.forecast_run_id=dfr.id WHERE dfr.merchant_user_id=? AND dfr.status='completed' AND dfm.target_metric='issued_value_cents' AND dfp.forecast_date>? AND dfr.id=(SELECT MAX(r2.id) FROM demand_forecast_runs r2 WHERE r2.merchant_user_id=dfr.merchant_user_id AND r2.model_id=dfr.model_id AND r2.status='completed')");$forecastStmt->execute([(int)$merchantId,$date]);$forecast=(int)round((float)$forecastStmt->fetchColumn());$publicId=mg_intelligence_uuid();$pdo->prepare("INSERT INTO merchant_intelligence_snapshots (public_id,merchant_user_id,snapshot_date,period_days,score_version,demand_score,engagement_score,fulfillment_score,redemption_score,growth_rate,forecast_value_cents,insights_json,created_at) VALUES (?,?,?,?,?,?,?,?,?,?,?,?,NOW()) ON DUPLICATE KEY UPDATE demand_score=VALUES(demand_score),engagement_score=VALUES(engagement_score),fulfillment_score=VALUES(fulfillment_score),redemption_score=VALUES(redemption_score),growth_rate=VALUES(growth_rate),forecast_value_cents=VALUES(forecast_value_cents),insights_json=VALUES(insights_json)")->execute([$publicId,(int)$merchantId,$date,$period,'1.0',$demand,$engagement,$fulfillment,$redemption,$growth,$forecast,json_encode($insights,JSON_UNESCAPED_SLASHES)]);}echo "Built intelligence snapshots for ".count($merchants)." merchants.\n";
